import{_ as t,o as r,c as e,ae as l}from"./chunks/framework.BzQXgbNp.js";const u=JSON.parse('{"title":"🧭 基礎傳送與定位系統","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Teleport-System.md","filePath":"Mc-Teleport-System.md"}'),s={name:"Mc-Teleport-System.md"};function n(i,o,a,g,c,d){return r(),e("div",null,[...o[0]||(o[0]=[l('<h1 id="🧭-基礎傳送與定位系統" tabindex="-1">🧭 基礎傳送與定位系統 <a class="header-anchor" href="#🧭-基礎傳送與定位系統" aria-label="Permalink to &quot;🧭 基礎傳送與定位系統&quot;">​</a></h1><p>本伺服器提供了完善且安全的傳送與地標定位系統，包括玩家間傳送請求 (TPA)、家園點 (Homes)、公共地標 (Warps) 以及隨機傳送 (RTP)。</p><hr><h2 id="👥-1-玩家間傳送-tpa-tpahere" tabindex="-1">👥 1. 玩家間傳送 (TPA / TPAHere) <a class="header-anchor" href="#👥-1-玩家間傳送-tpa-tpahere" aria-label="Permalink to &quot;👥 1. 玩家間傳送 (TPA / TPAHere)&quot;">​</a></h2><ul><li><strong>發送傳送請求</strong>： <ul><li><strong><code>/tpa &lt;玩家名稱&gt;</code></strong>：請求傳送至該玩家的位置。</li><li><strong><code>/tpahere &lt;玩家名稱&gt;</code></strong>：請求將該玩家拉到您的身邊。</li></ul></li><li><strong>取消傳送請求</strong>： <ul><li>發送請求後，發送方的聊天欄中會顯示 <strong><code>[取消]</code></strong> 按鈕。若在對方接受前點擊該按鈕，或輸入 <strong><code>/tpa cancel &lt;玩家&gt;</code></strong>，即可取消此傳送請求。</li></ul></li><li><strong>接受與拒絕</strong>： <ul><li>接收方聊天欄會提供 <strong><code>[接受]</code></strong> 與 <strong><code>[拒絕]</code></strong> 按鈕。點選按鈕或手動輸入 <strong><code>/tpaccept</code></strong> / <strong><code>/tpdeny</code></strong> 進行回覆。</li><li>請求會在 <strong>60 秒後</strong> 自動過期失效。</li></ul></li><li><strong>猶豫期與位置變動監控 ( warmup )</strong>： <ul><li>接受傳送請求後，將進入 <strong>5 秒猶豫期</strong>。</li><li>傳送玩家必須在 5 秒內保持原地不動。若系統檢測到玩家座標 (X, Y, Z) 發生移動，傳送將被自動取消並提示 <code>§c[傳送取消] 檢測到您的位置發生移動！</code>。</li><li>若玩家或目標在 5 秒內突然下線，傳送也會自動取消並清理任務。</li></ul></li></ul><hr><h2 id="🏠-2-個人家園-player-homes" tabindex="-1">🏠 2. 個人家園 (Player Homes) <a class="header-anchor" href="#🏠-2-個人家園-player-homes" aria-label="Permalink to &quot;🏠 2. 個人家園 (Player Homes)&quot;">​</a></h2><ul><li><strong>建立家園點</strong>： <ul><li>站在您想要記錄的位置，輸入指令 <strong><code>/sethome &lt;名稱&gt;</code></strong> 即可建立家園點（名稱支援<strong>中文</strong>、英文與底線）。</li><li>傳送到家園：輸入 <strong><code>/home &lt;名稱&gt;</code></strong>。</li><li>刪除家園：輸入 <strong><code>/delhome &lt;名稱&gt;</code></strong>。</li><li>列出所有家園：輸入 <strong><code>/home</code></strong>。</li></ul></li><li><strong>數量限制與收費規則</strong>： <ul><li>每位玩家預設可設定 <strong>2 個免費的 Home</strong>。</li><li>超過 2 個後，每新建一個未曾存在的家（新名稱），將從玩家的遊戲帳戶中扣除 <strong>$300 遊戲幣</strong>（餘額不足會被拒絕）。</li><li>如果是覆蓋更新已有的同名家園（例如對已存在的 <code>home1</code> 重新 <code>/sethome home1</code>），則是<strong>完全免費</strong>的。</li><li>每個玩家的家園上限最高為 <strong>15 個</strong>。</li></ul></li><li><strong>網頁端管理</strong>： <ul><li>登入網頁版儀表板，在「傳送點管理」頁面，您可以一目了然所有家園點的座標與世界維度。</li><li>您可以在網頁上一鍵點選「刪除家園」（需二次彈出視窗確認）。</li></ul></li></ul><hr><h2 id="🏁-3-公共地標-warps" tabindex="-1">🏁 3. 公共地標 (Warps) <a class="header-anchor" href="#🏁-3-公共地標-warps" aria-label="Permalink to &quot;🏁 3. 公共地標 (Warps)&quot;">​</a></h2><ul><li><strong>地標清單</strong>：輸入 <strong><code>/warp</code></strong> 可列出全伺服器的公共地標。</li><li><strong>地標傳送</strong>：輸入 <strong><code>/warp &lt;地標名稱&gt;</code></strong> 瞬間飛往地標。</li><li><strong>地標建立與刪除 (管理員專用)</strong>： <ul><li>只有 OP/管理員能使用 <code>/setwarp &lt;名稱&gt;</code> 建立公共地標，或使用 <code>/delwarp &lt;名稱&gt;</code> 進行刪除。</li><li>管理員登入網頁後，可於「傳送點管理」中檢視並刪除所有 Warp 地標（需二次確認）。</li></ul></li></ul><hr><h2 id="🎲-4-隨機傳送-rtp" tabindex="-1">🎲 4. 隨機傳送 (RTP) <a class="header-anchor" href="#🎲-4-隨機傳送-rtp" aria-label="Permalink to &quot;🎲 4. 隨機傳送 (RTP)&quot;">​</a></h2><ul><li><strong>指令語法</strong>：在聊天欄輸入 <strong><code>/rtp</code></strong> 即可傳送。</li><li><strong>傳送冷卻 (Cooldown)</strong>：隨機傳送設有 <strong>60 秒</strong> 的冷卻時間，防止頻繁使用導致伺服器區塊生成卡頓。</li><li><strong>隨機半徑</strong>：在以您為中心半徑 <strong>3000 格</strong> 範圍內隨機尋找安全地點。</li><li><strong>安全落地機制</strong>： <ul><li>隨機傳送僅會將您傳送至<strong>固體陸地表面</strong>，絕對不會把您傳送到地底、水上或岩漿上。</li><li><strong>維度與地獄支援</strong>：支持主世界、地獄與終界。針對地獄 (Nether)，系統會自動避開上方基岩，從 <strong>Y=120 以下</strong> 開始往下掃描安全平台落地。</li></ul></li></ul><hr><h2 id="💀-5-返回點與死亡點傳送-back" tabindex="-1">💀 5. 返回點與死亡點傳送 (/back) <a class="header-anchor" href="#💀-5-返回點與死亡點傳送-back" aria-label="Permalink to &quot;💀 5. 返回點與死亡點傳送 (/back)&quot;">​</a></h2><ul><li><strong>指令語法</strong>：在聊天欄輸入 <strong><code>/back</code></strong> 即可傳送回上一次的地點或死亡點。</li><li><strong>自動記錄機制</strong>： <ul><li><strong>死亡點</strong>：當您在遊戲中不幸意外死亡時，系統會自動將您的死亡座標 (維度、X, Y, Z) 記錄為返回點。</li><li><strong>主動傳送點</strong>：當您執行任何傳送指令（<code>/tpa</code>、<code>/tpahere</code>、<code>/home</code>、<code>/warp</code>、<code>/rtp</code>、<code>/shop</code> 商店傳送）時，傳送發起瞬間的原始座標將自動記錄為返回點。</li></ul></li><li><strong>5 秒猶豫期與位移防護</strong>： <ul><li>執行 <code>/back</code> 後進入 <strong>5 秒原地靜止猶豫期</strong>。</li><li>期間玩家座標若發生移動，傳送將自動取消；傳送成功後會播放 SoundEvents 並顯示 <code>§b[Craft-Core] §a成功返回上一次的地點/死亡點！</code>。</li></ul></li></ul>',17)])])}const p=t(s,[["render",n]]);export{u as __pageData,p as default};
